head.script:
scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + new Date(scwin.vCurDate.substring(0, 4), scwin.vCurDate.substring(4, 6), 0).getDate();;  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)

scwin.districtCd = "";
scwin.rowFlag = "";  // 등록, 수정 후 저장 안하고 다른 master row 선택 불가능 구분자
scwin.pos_grid = 0;
scwin.type = "";
scwin.initCnt = 0;

scwin.onpageload = function () {
    let memJson = $c.data.getMemInfo();
    scwin.districtCd = memJson.districtCd;

    const codeOptions = [
        { grpCd: "LO102", compID: "gr_master:basisUnitCd,gr_master:scBasisUnitCd", opt: { "range": "2,L" } },
        { grpCd: "OP632", compID: "gr_master:basisYn" },
        { grpCd: "OP283", compID: "gr_master:jangbiCd1,gr_master:jangbiCd2,gr_master:jangbiCd3" },
        { grpCd: "OP241", compID: "lc_con_wrkMthdCd" }
    ]
    $c.data.setCommonCode(codeOptions, scwin.onLoadCommonCode);

    const codeOptions2 = [
        {
            method: "getLuxeComboData",
            param1: "GoodsSurchargeWorkStepEBC",
            param2: "retriveDistrictCodeList",
            compID: "lc_con_districtCd"
        }
    ];
    $c.data.setGauceUtil(codeOptions2, scwin.chkInit);
    scwin.chkInit();
};

scwin.onLoadCommonCode = function () {
    scwin.chkInit();
};

scwin.onUdcCompleted = function () {
    scwin.chkInit();
};

scwin.chkInit = function () {
    if (++scwin.initCnt >= 4) {
        scwin.f_FieldClear();
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if (lc_con_districtCd.getValue() == "") {
        await $c.win.alert("권역을 선택해 주십시오.");
        lc_con_districtCd.focus();
        return;
    }
    if (lc_con_wrkMthdCd.getValue() == "") {
        await $c.win.alert("작업방법을 선택해 주십시오.");
        lc_con_wrkMthdCd.focus();
        return;
    }
    if (ica_con_adptDt.getValue() == "") {
        await $c.win.alert("적용일자를 선택해 주십시오.");
        ica_con_adptDt.focus();
        return;
    }

    $c.sbm.execute(sbm_retrieve);
};


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    scwin.pos_grid = ds_master.getRowPosition();
    let setGoods = ds_master.getCellData(scwin.pos_grid, "goodsCd");
    //변경한 데이터가 있는지 체크한다. 

    if (ds_master.getModifiedIndex().length == 0) {
        await $c.win.alert(MSG_CM_ERR_001, ["하역노임기본요율"]);
        return;
    }

    for (let i = 0; i < ds_master.getRowCount(); i++) {

        if (ds_master.getCellData(i, "adptStDt") == "") {
            await $c.win.alert("요율의 적용시작일자를 입력해 주세요.");
            gr_master.setFocusedCell(i, "adptStDt");
            return false;
        }
        if (ds_master.getCellData(i, "adptEndDt") == "") {
            await $c.win.alert("요율의 적용종료일자를 입력해 주세요.");
            gr_master.setFocusedCell(i, "adptEndDt");
            return false;
        }
    }

    let chkAlert = await $c.win.confirm("저장하시겠습니까?");
    if (chkAlert) {
        $c.sbm.execute(sbm_save);
    }
};

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = function () {
    scwin.f_openCommonPopUp(3, '', '', 'T', 'T');
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {
    let row = ds_master.getRowPosition();
    let goodsCd = ds_master.getCellData(row, "goodsCd");

    let chkAlert = await $c.win.confirm("선택한 품명 [ " + ds_master.getCellData(row, "goodsNm") + " ] 에 대한 요율을 삭제하시겠습니까?");
    if (chkAlert) {

        for (let i = 0; i < ds_master.getRowCount(); i++) {

            if (ds_master.getCellData(i, "goodsCd") == goodsCd) {
                ds_master.deleteRow(i);
            }
        }
    }
};


//-------------------------------------------------------------------------
// 요율 복사
//-------------------------------------------------------------------------
scwin.f_Copy = async function () {
    let vDistrictCd = dma_condition.get("districtCd"); 	//권역코드
    let vWrkMthdCd = dma_condition.get("wrkMthdCd");		//작업방법코드
    //let vAdptStDt = dma_condition.get("adptDt");		//원인적용시작일자
    //let vWageAgrmntDt = dma_condition.get("wageAgrmntDt");	//원인노임협약일자 
    let vAdptStDt = ds_master.getCellData(ds_master.getRowPosition(), "adptStDt");		//원인적용시작일자
    let vWageAgrmntDt = ds_master.getCellData(ds_master.getRowPosition(), "wageAgrmntDt");	//원인노임협약일자 
    let vGoodsCd = dma_condition.get("goodsCd");			//품목코드
    let vGoodsNm = dma_condition.get("goodsNm");			//품명  
    let win_url = "/ui/ds/op/adjmbd/wageadjmproc/op_403_01_02p.xml";

    let opts = {};
    opts.modal = true;
    opts.type = "browserPopup";
    opts.id = scwin.popupID || "pupup";
    opts.width = 800;
    opts.height = 300;
    opts.popupName = '하역노임기본요율복사';

    let param = {
        districtCd: vDistrictCd,
        wrkMthdCd: vWrkMthdCd,
        adptStDt: vAdptStDt,
        wageAgrmntDt: vWageAgrmntDt,
        goodsCd: vGoodsCd,
        goodsNm: vGoodsNm
    }

    rtnList = await $c.win.openPopup(win_url, opts, param);
};


//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    lc_con_districtCd.setValue("IHP");
    lc_con_wrkMthdCd.setValue("AA");
    ed_con_goodsCd.setValue("");
    ed_con_goodsNm.setValue("");
    ica_con_adptDt.setValue(scwin.vCurDate);
    ica_con_wageAgrmntDt.setValue("");
};

//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = async function () {
    let chkAlert = await $c.win.confirm("취소하시겠습니까?");
    if (chkAlert) {
        //ds_master.Undo(ds_master.RowPosition);
        $c.data.undoRow(ds_master);
    }
};


//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1:
            // 품명 조건검색 팝업
            udc_con_goodsCd.cfCommonPopUp(scwin.callbackCommGoodsInfo1, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;

        case 2:
            // 품명 조건검색 팝업
            udc_con_goodsCd.cfCommonPopUp(scwin.callbackCommGoodsInfo2, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;

        case 3:
            // 품명 조건검색 팝업
            udc_con_goodsCd.cfCommonPopUpAsync(null, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null).then((rtnList) => scwin.callbackCommGoodsInfo3(rtnList));
            break;
        default:
            break;
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');  // inObj가 코드 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');  // inObj가 코드명 필드일 경우 팝업
    }
};

//-------------------------------------------------------------------------
// 기본단위코드와 할증단위코드 동기화
//-------------------------------------------------------------------------
scwin.f_SelectUnitCd = function (row, colid) {
    if (colid == "basisUnitCd") {
        ds_master.setCellData(row, "scBasisUnitCd", ds_master.getCellData(row, "basisUnitCd"));
    }
};


//-------------------------------------------------------------------------
// 그리드에서 달력팝업 호출
//-------------------------------------------------------------------------
scwin.f_CalendarOpenPopup = function (row, colid) {
    if (colid == "goodsNm") {
        scwin.f_openCommonPopUp(2, "", "", "T", "T");
    }

    if (colid == "goodsCd") {
        scwin.f_openCommonPopUp(2, ds_master.getCellData(row, "goodsCd"), "", "T", "T");
    }

};

scwin.f_changeImage = function (Colid) {
};

scwin.f_toExcel = function () {
    const options = {
        "fileName": "하역노임 기본요율.xlsx",
        "sheetName": "하역노임 기본요율",
        "startRowIndex": 3,
        "startColumnIndex": 0,
        "colMerge": "true",
    };
    let totlaCol = gr_master.getTotalCol();
    let colSpan = 0;
    for (let idx = 0; idx < totlaCol; ++idx) {
        if (gr_master.getColumnVisible(idx)) {
            ++colSpan;
        }
    }

    const infoArr = [
        {
            "rowIndex": 0,
            "colIndex": 0,
            "rowSpan": 1,
            "colSpan": colSpan,
            "text": "하역노임 기본요율",
            "textAlign": "center",
            "drawBorder": "false",
            "bgColor": "yellow",
            "fontSize": "16px"
        }
    ];
    $c.data.downloadGridViewExcel(gr_master, options, infoArr);
};

/////////////////////////////////////////////////////////
//////////////// Callback EVENT START  //////////////////
/////////////////////////////////////////////////////////

scwin.callbackCommGoodsInfo1 = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_con_goodsCd, ed_con_goodsNm);  // 품명코드, 품명             
};

scwin.callbackCommGoodsInfo2 = async function (rtnList) {
    if (rtnList != null) {
        ds_master.setCellData(ds_master.getRowPosition(), "goodsCd", rtnList[0]);
        ds_master.setCellData(ds_master.getRowPosition(), "goodsNm", rtnList[1]);
        ds_master.setCellData(ds_master.getRowPosition(), "upGoodsNm", rtnList[5]);

        let row = ds_master.getMatchedIndex("selpchItemCd", rtnList[0]);

        if (row != "") {
            for (let i = 0; i < row.length; i++) {
                if (ds_master.getRowPosition() != row[i]) {
                    await $c.win.alert(row + "째 Row에 중복된 노임항목이 존재합니다.");
                    ds_master.setCellData(ds_master.getRowPosition(), "goodsCd", "");
                    ds_master.setCellData(ds_master.getRowPosition(), "goodsNm", "");
                    ds_master.setCellData(ds_master.getRowPosition(), "upGoodsNm", "");
                }
            }

        }
    } else {
        ds_master.setCellData(ds_master.getRowPosition(), "goodsCd", "");
        ds_master.setCellData(ds_master.getRowPosition(), "goodsNm", "");
        ds_master.setCellData(ds_master.getRowPosition(), "upGoodsNm", "");
    }
};

scwin.callbackCommGoodsInfo3 = async function (rtnList) {
    if (rtnList != null) {
        dma_condition.set("goodsCd2", rtnList[0]);
        if (dma_condition.get("goodsCd2") != "") {
            ds_existYn.removeAll();
            $c.sbm.execute(sbm_existYn);
        } else {
            return false;
        }
    } else {
        await $c.win.alert("신규 품목에 대한 요율을 등록하기 위해서\n해당 품목을 선택하여야 합니다.");
    }
};

/////////////////////////////////////////////////////////
//////////////// Callback EVENT END    //////////////////
/////////////////////////////////////////////////////////

/////////////////////////////////////////////////////////
//////////////// OBJECT EVENT START//////////////////////
/////////////////////////////////////////////////////////

scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_search_onclick = async function (e) {
    await scwin.f_Retrieve();
};

scwin.btn_Copy_onclick = function (e) {
    scwin.f_Copy();
};

scwin.btn_Create_onclick = function (e) {
    scwin.f_Create();
};

scwin.btn_Delete_onclick = function (e) {
    scwin.f_Delete();
};

scwin.btn_Cancel_onclick = function (e) {
    scwin.f_Cancel();
};

scwin.btn_Save_onclick = function (e) {
    scwin.f_Save();
};

scwin.udc_con_goodsCd_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_con_goodsCd.getValue(), ed_con_goodsNm.getValue(), 'T', 'T')
};

scwin.udc_con_goodsCd_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_con_goodsCd, ed_con_goodsNm, 1);
};

scwin.udc_con_goodsCd_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_con_goodsNm, ed_con_goodsCd, 1, false);
};

scwin.gr_master_onrowindexchange = function (rowIndex, oldRow) {
    if (ds_master.getCellData(rowIndex, "basisYn") == "1") {
        gr_master.setColumnReadOnly("basisWrkStpCd", false);
        gr_master.setColumnReadOnly("basisWrkStpCd2", false);
        gr_master.setColumnReadOnly("basisUprRt", true);
        gr_master.setColumnReadOnly("scBasisUprRt", true);
        gr_master.setColumnReadOnly("jangbiCd1", true);
        gr_master.setColumnReadOnly("jangbiAmt1", true);
        gr_master.setColumnReadOnly("jangbiRt1", true);
        gr_master.setColumnReadOnly("jangbiCd2", true);
        gr_master.setColumnReadOnly("jangbiAmt2", true);
        gr_master.setColumnReadOnly("jangbiRt2", true);
        gr_master.setColumnReadOnly("jangbiCd3", true);
        gr_master.setColumnReadOnly("jangbiAmt3", true);
        gr_master.setColumnReadOnly("jangbiRt3", true);
    } else {
        gr_master.setColumnReadOnly("basisWrkStpCd", false);
        gr_master.setColumnReadOnly("basisWrkStpCd2", false);
        gr_master.setColumnReadOnly("basisUprRt", false);
        gr_master.setColumnReadOnly("scBasisUprRt", false);
        gr_master.setColumnReadOnly("jangbiCd1", false);
        gr_master.setColumnReadOnly("jangbiAmt1", false);
        gr_master.setColumnReadOnly("jangbiRt1", false);
        gr_master.setColumnReadOnly("jangbiCd2", false);
        gr_master.setColumnReadOnly("jangbiAmt2", false);
        gr_master.setColumnReadOnly("jangbiRt2", false);
        gr_master.setColumnReadOnly("jangbiCd3", false);
        gr_master.setColumnReadOnly("jangbiAmt3", false);
        gr_master.setColumnReadOnly("jangbiRt3", false);
    }
};

scwin.gr_master_oneditend = function (rowIndex, columnIndex, value) {
    let inputType = gr_master.getColumnType(columnIndex);
    let colid = gr_master.getColumnID(columnIndex);
    if (inputType == "select") {
        scwin.f_SelectUnitCd(rowIndex, colid);
    }

    if (colid === "basisWrkStpCd2") {
        ds_master.setCellData(rowIndex, "basisWrkStpCd", value);
    } else if (colid === "basisWrkStpCd") {
        ds_master.setCellData(rowIndex, "basisWrkStpCd2", value);
    }
};

scwin.gr_master_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {
    let colid = gr_master.getColumnID(columnIndex);
    scwin.f_changeImage(colid);
};

scwin.gr_master_ontextimageclick = function (rowIndex, columnIndex) {
    let colid = gr_master.getColumnID(columnIndex);
    scwin.f_CalendarOpenPopup(rowIndex, colid);
};

/////////////////////////////////////////////////////////
//////////////// OBJECT EVENT END  //////////////////////
/////////////////////////////////////////////////////////

/////////////////////////////////////////////////////////
//////////////// Submission EVENT START  ////////////////
/////////////////////////////////////////////////////////

scwin.sbm_retrieve_submitdone = async function (e) {
    if (ds_master.getRowCount() == 0) {
        await $c.win.alert("조회된 내역이 없습니다.");
    }
};

/////////////////////////////////////////////////////////
//////////////// Submission EVENT END  //////////////////
/////////////////////////////////////////////////////////

scwin.sbm_retrieveWrkStp_submitdone = function (e) {
    for (let i = 0; i < ds_master.getRowCount(); i++) {
        ds_master.setCellData(i, "districtCd", lc_con_districtCd.getValue());
        ds_master.setCellData(i, "wrkMthdCd", lc_con_wrkMthdCd.getValue());
        ds_master.setCellData(i, "goodsCd", dma_condition.get("goodsCd2"));
        ds_master.setCellData(i, "adptEndDt", '99999999');
        ds_master.modifyRowStatus(i, "C");

        scwin.type = "create";
    }
};

scwin.sbm_existYn_submitdone = async function (e) {
    // sbm_retrieveWrkStp submitdone 으로 이동
    if (ds_existYn.getCellData(0, "existYn") == "Y") {
        await $c.win.alert("이미 요율이 존재하는 품명입니다.\n신규 품목을 선택해 주세요.");
        return;
    } else {
        ds_master.removeAll();
        $c.sbm.execute(sbm_retrieveWrkStp);
    }
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        await $c.win.alert(MSG_CM_INF_001); // 성공적으로 저장하였습니다 
        spa_cnt.setValue(ds_master.getRowCount());
        if (scwin.type == "create") {
            let setGoods = ds_master.getCellData(scwin.pos_grid, "goodsCd");
            ed_con_goodsCd.setValue(setGoods);
            scwin.f_chkOpenCommonPopUp(ed_con_goodsCd, ed_con_goodsNm, 1);
        }
        $c.sbm.execute(sbm_retrieve);
    }
};

/////////////////////////////////////////////////////////
//////////////// DataSet EVENT START  ///////////////////
/////////////////////////////////////////////////////////

scwin.ds_master_ondataload = function () {
    $c.gus.cfGoPrevPosition(gr_master, scwin.pos_grid);
    spa_cnt.setValue(ds_master.getRowCount());
    let allData = ds_master.getAllJSON();
    for (let idx = 0; idx < allData.length; ++idx) {
        ds_master.setCellData(idx, "basisWrkStpCd2", allData[idx].basisWrkStpCd);
    }
    ds_master.reform();
};

scwin.ds_master_oncelldatachange = async function (info) {
    //realRowIndex: 5, rowIndex: 5, colID: 'scBasisUprAmt', oldValue: '682', newValue: '34'
    let colid = info.colID;
    if (colid === "basisWrkStpCd2") {
        return;
    }
    let row = info.rowIndex;

    let goodsCd1 = ds_master.getCellData(row, "goodsCd");
    let adptStp1 = ds_master.getCellData(row, "basisWrkStpCd");
    let amt = null;

    for (let i = 0; i < ds_master.getRowCount(); i++) {
        if (ds_master.getCellData(i, "goodsCd") == goodsCd1 && ds_master.getCellData(i, "wrkStpCd") == adptStp1) {
            amt = $c.num.parseFloat(ds_master.getCellData(i, "basisUprAmt"), 0);
        }
    }

    if (colid == "basisWrkStpCd" && ds_master.getCellData(row, "basisYn") == 0 && amt === 0) {
        await $c.win.alert("기본에 대하여 금액을 설정해 주세요.");
        ds_master.setCellData(row, "basisWrkStpCd", "");
        ds_master.setCellData(row, "basisWrkStpCd2", "");
    }

    if (colid == "basisWrkStpCd" && ds_master.getCellData(row, "basisYn") == 1 && ds_master.getCellData(row, "basisWrkStpCd") != "") {
        await $c.win.alert("적용단계는 상세에서 선택해 주세요.");
        ds_master.setCellData(row, "basisWrkStpCd", "");
        ds_master.setCellData(row, "basisWrkStpCd2", "");
    }

    let val = null;
    let oldVal = null;
    let targetID = null;
    if (ds_master.getCellData(row, "basisYn") == 0) {
        switch (colid) {
            case "basisUprRt":
                targetID = "basisUprAmt";
                val = amt * $c.num.parseFloat(ds_master.getCellData(row, "basisUprRt"), 0) / 100;
                if (isNaN(val)) {
                    val = 0;
                }
                if (val == 0) {
                    ds_master.setCellData(row, colid, "0");
                } else {
                    oldVal = $c.num.parseFloat(ds_master.getCellData(row, targetID));
                    if (Math.abs(oldVal - val) < 0.0000002) {
                        break;
                    }
                }
                ds_master.setCellData(row, "basisUprAmt", val.toString());
                break;

            case "scBasisUprRt":
                targetID = "scBasisUprAmt";
                val = amt * $c.num.parseFloat(ds_master.getCellData(row, "scBasisUprRt"), 0) / 100;
                if (isNaN(val)) {
                    val = 0;
                }
                if (val == 0) {
                    ds_master.setCellData(row, colid, "0");
                } else {
                    oldVal = $c.num.parseFloat(ds_master.getCellData(row, targetID));
                    if (Math.abs(oldVal - val) < 0.0000002) {
                        break;
                    }
                }
                ds_master.setCellData(row, "scBasisUprAmt", val.toString());
                break;

            case "basisUprAmt":
                targetID = "basisUprRt";
                val = $c.num.parseFloat(ds_master.getCellData(row, "basisUprAmt"), 0) / amt * 100;
                if (isNaN(val)) {
                    val = 0;
                }
                oldVal = $c.num.parseFloat(ds_master.getCellData(row, targetID));
                if (Math.abs(oldVal - val) < 0.0000002) {
                    break;
                }
                ds_master.setCellData(row, "basisUprRt", val.toString());
                break;

            case "scBasisUprAmt":
                targetID = "scBasisUprRt";
                val = $c.num.parseFloat(ds_master.getCellData(row, "scBasisUprAmt"), 0) / amt * 100;
                if (isNaN(val)) {
                    val = 0;
                }
                oldVal = $c.num.parseFloat(ds_master.getCellData(row, targetID));
                if (Math.abs(oldVal - val) < 0.0000002) {
                    break;
                }
                ds_master.setCellData(row, "scBasisUprRt", val.toString());
                break;

            case "jangbiAmt1":
                targetID = "jangbiRt1";
                val = $c.num.parseFloat(ds_master.getCellData(row, "jangbiAmt1"), 0) / amt * 100;
                if (isNaN(val)) {
                    val = 0;
                }
                oldVal = $c.num.parseFloat(ds_master.getCellData(row, targetID));
                if (Math.abs(oldVal - val) < 0.0000002) {
                    break;
                }
                ds_master.setCellData(row, "jangbiRt1", val.toString());
                break;

            case "jangbiAmt2":
                targetID = "jangbiRt2";
                val = $c.num.parseFloat(ds_master.getCellData(row, "jangbiAmt2"), 0) / amt * 100;
                if (isNaN(val)) {
                    val = 0;
                }
                oldVal = $c.num.parseFloat(ds_master.getCellData(row, targetID));
                if (Math.abs(oldVal - val) < 0.0000002) {
                    break;
                }
                ds_master.setCellData(row, "jangbiRt2", val.toString());
                break;

            case "jangbiAmt3":
                targetID = "jangbiRt3";
                val = $c.num.parseFloat(ds_master.getCellData(row, "jangbiAmt3"), 0) / amt * 100;
                if (isNaN(val)) {
                    val = 0;
                }
                oldVal = $c.num.parseFloat(ds_master.getCellData(row, targetID));
                if (Math.abs(oldVal - val) < 0.0000002) {
                    break;
                }
                ds_master.setCellData(row, "jangbiRt3", val.toString());
                break;

            case "jangbiRt1":
                targetID = "jangbiAmt1";
                val = amt * $c.num.parseFloat(ds_master.getCellData(row, "jangbiRt1"), 0) / 100;
                if (isNaN(val)) {
                    val = 0;
                }
                if (val == 0) {
                    ds_master.setCellData(row, colid, "0");
                } else {
                    oldVal = $c.num.parseFloat(ds_master.getCellData(row, targetID));
                    if (Math.abs(oldVal - val) < 0.0000002) {
                        break;
                    }
                }
                ds_master.setCellData(row, "jangbiAmt1", val.toString());
                break;

            case "jangbiRt2":
                targetID = "jangbiAmt2";
                val = amt * $c.num.parseFloat(ds_master.getCellData(row, "jangbiRt2"), 0) / 100;
                if (isNaN(val)) {
                    val = 0;
                }
                if (val == 0) {
                    ds_master.setCellData(row, colid, "0");
                } else {
                    oldVal = $c.num.parseFloat(ds_master.getCellData(row, targetID));
                    if (Math.abs(oldVal - val) < 0.0000002) {
                        break;
                    }
                }
                ds_master.setCellData(row, "jangbiAmt2", val.toString());
                break;

            case "jangbiRt3":
                targetID = "jangbiAmt3";
                val = amt * $c.num.parseFloat(ds_master.getCellData(row, "jangbiRt3"), 0) / 100;
                if (isNaN(val)) {
                    val = 0;
                }
                if (val == 0) {
                    ds_master.setCellData(row, colid, "0");
                } else {
                    oldVal = $c.num.parseFloat(ds_master.getCellData(row, targetID));
                    if (Math.abs(oldVal - val) < 0.0000002) {
                        break;
                    }
                }
                ds_master.setCellData(row, "jangbiAmt3", val.toString());
                break;
        }
    }

    if (row == 0 && colid == "adptStDt") {
        for (let i = 0; i < ds_master.getRowCount(); i++) {
            ds_master.setCellData(i, "adptStDt", ds_master.getCellData(0, "adptStDt"));
        }
    } else if (row == 0 && colid == "wageAgrmntDt") {
        for (let i = 0; i < ds_master.getRowCount(); i++) {
            ds_master.setCellData(i, "wageAgrmntDt", ds_master.getCellData(0, "wageAgrmntDt"));
        }
    } else if (colid == "goodsCd") {
        scwin.f_openCommonPopUp(2, ds_master.getCellData(row, "goodsCd"), ds_master.getCellData(row, "goodsNm"), 'T', 'T');
    }
};

