scwin.basisWrkStpCdFormatter = function (text, formatted, row, col) {
    if (formatted === "없음") {
        return "";
    }
    return formatted;
};

scwin.gr_master_onafteredit = function (row, col, value) {
    let colid = gr_master.getColumnID(col);
    switch (colid) {
        case "basisUprAmt":
        case "basisUprRt":
        case "scBasisUprAmt":
        case "scBasisUprRt":
        case "jangbiAmt1":
        case "jangbiRt1":
        case "jangbiAmt2":
        case "jangbiRt2":
        case "jangbiAmt3":
        case "jangbiRt3":
            if (value === "" || isNaN(value)) {
                ds_master.setCellData(row, colid, "0");
            }
            break;
    }
};

scwin.dateValidate = function (text) {
    return text;
};
